{"file_path": "/project/kotlinx-coroutines-core/common/test/flow/operators/TakeOnCompletionFirstTest.kt", "content": "package kotlinx.coroutines.flow

import kotlinx.coroutines.testing.*
import kotlinx.coroutines.*
import kotlin.test.*

/**
 * Tests for the bug fix where `take` was incorrectly swallowing downstream AbortFlowException.
 * 
 * The issue was that `take` used the flow's receiver (the downstream collector) as the owner
 * of its AbortFlowException. When downstream (like `first()`) also threw AbortFlowException
 * with the same collector as owner, `take` would incorrectly swallow it.
 * 
 * The fix creates a unique owner object for `take`'s AbortFlowException.
 * 
 * See: https://github.com/Kotlin/kotlinx.coroutines/issues/4035
 */
class TakeOnCompletionFirstTest : TestBase() {

    /**
     * Original reproducer from the issue.
     * This used to hang forever because take swallowed first's abort exception,
     * causing onCompletion to see null (normal completion) and call awaitCancellation.
     */
    @Test
    fun testTakeOneOnCompletionFirst() = runTest {
        val result = flowOf(1)
            .take(1)
            .onCompletion { cause ->
                // With the fix, cause should NOT be null - it should be AbortFlowException from first()
                assertNotNull(cause, "onCompletion should see the abort exception from first()")
            }
            .first()
        assertEquals(1, result)
    }

    /**
     * Another reproducer from the issue - take(100) with a 3-element flow.
     * take(100) won't reach its limit, so it never throws its own AbortFlowException.
     * But first() will throw after the first element.
     */
    @Test
    fun testTakeHighCountOnCompletionFirst() = runTest {
        val result = flowOf(1, 2, 3)
            .take(100) // won't hang if the fix is correct
            .onCompletion { cause ->
                // With the fix, cause should NOT be null
                assertNotNull(cause, "onCompletion should see the abort exception from first()")
            }
            .first()
        assertEquals(1, result)
    }

    /**
     * Verify that adding onEach between take and onCompletion still works.
     * This was one of the cases that didn't hang even before the fix.
     */
    @Test
    fun testTakeOnEachOnCompletionFirst() = runTest {
        val result = flowOf(1)
            .take(1)
            .onEach { } // no-op operator
            .onCompletion { cause ->
                assertNotNull(cause, "onCompletion should see the abort exception from first()")
            }
            .first()
        assertEquals(1, result)
    }

    /**
     * Without take, onCompletion should still see the abort exception from first().
     */
    @Test
    fun testOnCompletionFirstWithoutTake() = runTest {
        val result = flowOf(1)
            .onCompletion { cause ->
                assertNotNull(cause, "onCompletion should see the abort exception from first()")
            }
            .first()
        assertEquals(1, result)
    }

    /**
     * Test that take still works correctly in isolation.
     */
    @Test
    fun testTakeBasic() = runTest {
        val result = flowOf(1, 2, 3).take(2).toList()
        assertEquals(listOf(1, 2), result)
    }

    /**
     * Test take(1) followed directly by first() without onCompletion.
     */
    @Test
    fun testTakeFirst() = runTest {
        val result = flowOf(1, 2, 3).take(1).first()
        assertEquals(1, result)
    }

    /**
     * Test take with onCompletion when collecting all elements (no abort from downstream).
     */
    @Test
    fun testTakeOnCompletionCollectAll() = runTest {
        val result = flowOf(1, 2, 3)
            .take(2)
            .onCompletion { cause ->
                // take completed normally, no downstream abort
                assertNull(cause, "onCompletion should see null for normal completion")
            }
            .toList()
        assertEquals(listOf(1, 2), result)
    }

    /**
     * Test that firstOrNull works correctly with take and onCompletion.
     */
    @Test
    fun testTakeOnCompletionFirstOrNull() = runTest {
        val result = flowOf(1)
            .take(1)
            .onCompletion { cause ->
                assertNotNull(cause, "onCompletion should see the abort exception from firstOrNull()")
            }
            .firstOrNull()
        assertEquals(1, result)
    }

    /**
     * Test nested takes with first.
     */
    @Test
    fun testNestedTakeOnCompletionFirst() = runTest {
        val result = flowOf(1, 2, 3)
            .take(2)
            .take(1)
            .onCompletion { cause ->
                assertNotNull(cause, "onCompletion should see the abort exception")
            }
            .first()
        assertEquals(1, result)
    }
}
"}

